import heapq

def minPath(grid, k):
    n = len(grid)
    heap = []
    for i in range(n):
        for j in range(n):
            heapq.heappush(heap, ([grid[i][j]], i, j, 1))
    while heap:
        path, i, j, t = heapq.heappop(heap)
        if t == k:
            return path
        for di, dj in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
            ni, nj = i + di, j + dj
            if 0 <= ni < n and 0 <= nj < n:
                new_path = path.copy()
                new_path.append(grid[ni][nj])
                heapq.heappush(heap, (new_path, ni, nj, t + 1))
    return []
